// Busca emails não lidos das últimas 24h e classifica com Claude
const tokenResp = await fetch('https://oauth2.googleapis.com/token', {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GOOGLE_CLIENT_ID,
    client_secret: $env.GOOGLE_CLIENT_SECRET,
    refresh_token: $env.GOOGLE_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  })
});
const { access_token } = await tokenResp.json();

// Busca emails não lidos (últimas 24h)
const r = await fetch('https://gmail.googleapis.com/gmail/v1/users/me/messages?maxResults=20&q=is:unread newer_than:1d', {
  headers: { 'Authorization': `Bearer ${access_token}` }
});
const data = await r.json();
const mensagens = data.messages || [];

if (mensagens.length === 0) {
  return [{ json: { resumo: '📧 Sem emails não lidos nas últimas 24h.' } }];
}

// Busca detalhes de até 10 emails
const detalhes = await Promise.all(mensagens.slice(0, 10).map(async m => {
  const r2 = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages/${m.id}?format=metadata&metadataHeaders=From&metadataHeaders=Subject&metadataHeaders=Date`, {
    headers: { 'Authorization': `Bearer ${access_token}` }
  });
  const msg = await r2.json();
  const h = msg.payload?.headers || [];
  return {
    id: m.id,
    from: h.find(x => x.name === 'From')?.value || '?',
    subject: h.find(x => x.name === 'Subject')?.value || '?',
    snippet: msg.snippet || ''
  };
}));

return [{ json: { emails: detalhes, total: mensagens.length, access_token } }];

const resp = $input.first().json;
const classificacao = resp.choices?.[0]?.message?.content || resp.error?.message || '';
const total = $('Buscar Emails').first().json.total;
return [{ json: { resumo: `📧 ${total} email(s) não lido(s):\n\n${classificacao}` } }];
